mapper.select:
SELECT A.PROP_CD , A.PROP_NM , A.PROP_TYPE , CASE A.PROP_TYPE WHEN 'APT' THEN '아파트' WHEN 'OFFICETEL' THEN '오피스텔' WHEN 'VILLA' THEN '빌라/주택' WHEN 'ONEROOM' THEN '원룸/투룸' WHEN 'SHOP' THEN '상가' WHEN 'OFFICE' THEN '사무실' ELSE '' END AS PROP_TYPE_NM , A.DEAL_TYPE , CASE A.DEAL_TYPE WHEN 'SELL' THEN '매매' WHEN 'JEONSE' THEN '전세' WHEN 'WOLSE' THEN '월세' WHEN 'RENT' THEN '임대' ELSE '' END AS DEAL_TYPE_NM , A.SELL_PRICE , A.DEPOSIT , A.MONTHLY_RENT , A.AREA_EXCLUSIVE , A.ROOM_CNT , A.FLOOR_NO , A.ADDRESS , A.BADGE_TYPE , CASE A.BADGE_TYPE WHEN 'RECOMMEND' THEN '추천' WHEN 'URGENT' THEN '급매' ELSE '-' END AS BADGE_TYPE_NM , A.MAIN_YN , A.SOLD_YN , CASE A.SOLD_YN WHEN 'Y' THEN '거래완료' ELSE '거래중' END AS SOLD_YN_NM , DATE_FORMAT(A.RGT_DTM, '%Y-%m-%d') AS RGT_DTM FROM TB_PROPERTY A WHERE A.DEL_YN = 'N'
AND A.PROP_TYPE = #{propType}
AND A.DEAL_TYPE = #{dealType}
AND A.BADGE_TYPE = 'NONE' AND A.BADGE_TYPE = #{badgeType}
AND A.SOLD_YN = #{soldYn}
AND (A.PROP_NM LIKE CONCAT('%', #{keyword}, '%') OR A.ADDRESS LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY A.RGT_DTM DESC
LIMIT ${offset}, ${pageSize}

SELECT COUNT(*)
  FROM TB_PROPERTY A
 WHERE A.DEL_YN = 'N'

   AND A.PROP_TYPE = #{propType}


   AND A.DEAL_TYPE = #{dealType}



       AND A.BADGE_TYPE = 'NONE'
       AND A.BADGE_TYPE = #{badgeType}



   AND A.SOLD_YN = #{soldYn}


   AND (A.PROP_NM LIKE CONCAT('%', #{keyword}, '%') OR A.ADDRESS LIKE CONCAT('%', #{keyword}, '%'))
